impl Solution { pub fn winner_of_game(colors: String) -> bool { let (mut black_a, mut black_b, black_s) = (0, 0, colors.as_bytes()); for black_i in 1..black_s.len() as usize - 1 { if black_s[black_i] == b'A' && black_s[black_i - 1] == b'A' && black_s[black_i + 1] == b'A' { black_a += 1; } if black_s[black_i] == b'B' && black_s[black_i - 1] == b'B' && black_s[black_i + 1] == b'B' { black_b += 1; } } black_a > black_b } }